INSERT INTO flashcards (id, term, definition, hint_1, hint_2, hint_3, module_id, keywords, tags, category, difficulty_level, is_published, review_status) VALUES
('fb02b000-0000-0000-0000-000000000001','Sole Proprietorship','The simplest and most common business form: one owner who is legally the same as the business and bears unlimited personal liability.','The owner and business are one.',NULL,NULL,NULL,ARRAY['sole proprietorship','entity','liability']::text[],ARRAY['fs-flashcards','fs-m11']::text[],'fs:f500000b-0000-0000-0000-00000000000b','beginner',true,'approved'),
('fb02b000-0000-0000-0000-000000000002','Partnership','A business owned by two or more people working for a profit. General partners have unlimited, joint-and-several liability.','Two or more owners, for profit.',NULL,NULL,NULL,ARRAY['partnership','entity']::text[],ARRAY['fs-flashcards','fs-m11']::text[],'fs:f500000b-0000-0000-0000-00000000000b','beginner',true,'approved'),
('fb02b000-0000-0000-0000-000000000003','Corporation','A legal entity separate from its owners (shareholders). It can issue stock and generally limits owner liability to their investment.','Exists independently; can sell stock.',NULL,NULL,NULL,ARRAY['corporation','stock','entity']::text[],ARRAY['fs-flashcards','fs-m11']::text[],'fs:f500000b-0000-0000-0000-00000000000b','beginner',true,'approved'),
('fb02b000-0000-0000-0000-000000000004','LLC / PLLC','Limited Liability Company — limits members'' liability to their investment. A PLLC is the professional form used for licensed surveying practice.','Limited liability; PLLC = professional.',NULL,NULL,NULL,ARRAY['llc','pllc','liability']::text[],ARRAY['fs-flashcards','fs-m11']::text[],'fs:f500000b-0000-0000-0000-00000000000b','intermediate',true,'approved'),
('fb02b000-0000-0000-0000-000000000005','Professional Corporation (PC)','A corporation organized to provide licensed professional services, with a licensed professional in responsible charge; owner liability is limited (except for one''s own malpractice).','Corporate form for licensed practice.',NULL,NULL,NULL,ARRAY['pc','professional corporation']::text[],ARRAY['fs-flashcards','fs-m11']::text[],'fs:f500000b-0000-0000-0000-00000000000b','intermediate',true,'approved'),
('fb02b000-0000-0000-0000-000000000006','Consideration','The value each party exchanges and bargains for in a contract — money, goods, services, or a promise. A required element of a valid contract.','The value exchanged.',NULL,NULL,NULL,ARRAY['consideration','contract','value']::text[],ARRAY['fs-flashcards','fs-m11']::text[],'fs:f500000b-0000-0000-0000-00000000000b','intermediate',true,'approved'),
('fb02b000-0000-0000-0000-000000000007','Elements of a Valid Contract','Offer, acceptance, consideration, capacity, and legality (lawful purpose). All five must be present for an enforceable contract.','Offer, acceptance, consideration, capacity, legality.',NULL,NULL,NULL,ARRAY['contract','elements']::text[],ARRAY['fs-flashcards','fs-m11']::text[],'fs:f500000b-0000-0000-0000-00000000000b','intermediate',true,'approved'),
('fb02b000-0000-0000-0000-000000000008','Breach of Contract','Failure to perform a contractual obligation. Remedies include monetary damages, specific performance, or rescission.','Failure to perform; damages/performance/rescission.',NULL,NULL,NULL,ARRAY['breach','contract','remedy']::text[],ARRAY['fs-flashcards','fs-m11']::text[],'fs:f500000b-0000-0000-0000-00000000000b','intermediate',true,'approved'),
('fb02b000-0000-0000-0000-000000000009','Simple Interest','Interest charged only on the principal (or remaining balance): I = P·i·n. It does not compound.','Interest on principal only.',NULL,NULL,NULL,ARRAY['simple interest','economics']::text[],ARRAY['fs-flashcards','fs-m11']::text[],'fs:f500000b-0000-0000-0000-00000000000b','beginner',true,'approved'),
('fb02b000-0000-0000-0000-00000000000a','Compound Interest','Interest earned on principal plus accumulated interest. Future worth of a single sum: F = P(1 + i)^n.','F = P(1+i)^n.',NULL,NULL,NULL,ARRAY['compound interest','future worth']::text[],ARRAY['fs-flashcards','fs-m11']::text[],'fs:f500000b-0000-0000-0000-00000000000b','intermediate',true,'approved'),
('fb02b000-0000-0000-0000-00000000000b','Present Worth','The value today of a future amount, discounted at rate i: P = F / (1 + i)^n.','P = F/(1+i)^n.',NULL,NULL,NULL,ARRAY['present worth','discount']::text[],ARRAY['fs-flashcards','fs-m11']::text[],'fs:f500000b-0000-0000-0000-00000000000b','intermediate',true,'approved'),
('fb02b000-0000-0000-0000-00000000000c','Annuity (Uniform Series)','A series of equal end-of-period payments A. Future worth F = A·[((1+i)^n − 1)/i].','Equal periodic payments.',NULL,NULL,NULL,ARRAY['annuity','uniform series']::text[],ARRAY['fs-flashcards','fs-m11']::text[],'fs:f500000b-0000-0000-0000-00000000000b','advanced',true,'approved'),
('fb02b000-0000-0000-0000-00000000000d','Straight-Line Depreciation','Equal annual loss of value over an asset''s life: D = (cost − salvage) / life. Book value = cost − k·D after k years.','D = (C − S)/n.',NULL,NULL,NULL,ARRAY['depreciation','straight-line']::text[],ARRAY['fs-flashcards','fs-m11']::text[],'fs:f500000b-0000-0000-0000-00000000000b','beginner',true,'approved'),
('fb02b000-0000-0000-0000-00000000000e','Standard of Care','The skill and diligence a reasonably prudent surveyor would exercise under similar conditions. It is the benchmark for professional liability.','Reasonably prudent surveyor.',NULL,NULL,NULL,ARRAY['standard of care','liability']::text[],ARRAY['fs-flashcards','fs-m11']::text[],'fs:f500000b-0000-0000-0000-00000000000b','intermediate',true,'approved'),
('fb02b000-0000-0000-0000-00000000000f','Negligence','Failure to meet the standard of care that causes damage. A surveyor is liable for negligence — not for failing to be perfect.','Falling below the standard of care.',NULL,NULL,NULL,ARRAY['negligence','liability']::text[],ARRAY['fs-flashcards','fs-m11']::text[],'fs:f500000b-0000-0000-0000-00000000000b','intermediate',true,'approved'),
('fb02b000-0000-0000-0000-000000000010','NCEES Model Rules','The model Rules of Professional Conduct most state boards adopt. Paramount duty: safeguard the public''s health, safety, and welfare.','Public health, safety & welfare first.',NULL,NULL,NULL,ARRAY['model rules','ethics','ncees']::text[],ARRAY['fs-flashcards','fs-m11']::text[],'fs:f500000b-0000-0000-0000-00000000000b','intermediate',true,'approved'),
('fb02b000-0000-0000-0000-000000000011','Conflict of Interest','A situation that could compromise professional judgment. The Model Rules require avoiding conflicts and, if unavoidable, disclosing them fully to all affected parties.','Avoid; if unavoidable, disclose fully.',NULL,NULL,NULL,ARRAY['conflict of interest','ethics']::text[],ARRAY['fs-flashcards','fs-m11']::text[],'fs:f500000b-0000-0000-0000-00000000000b','intermediate',true,'approved'),
('fb02b000-0000-0000-0000-000000000012','Confined Space','A space large enough to enter and work, with limited or restricted entry/exit, that is not designed for continuous occupancy (manhole, vault, tank).','Enter + limited exit + not for continuous occupancy.',NULL,NULL,NULL,ARRAY['confined space','osha','safety']::text[],ARRAY['fs-flashcards','fs-m11']::text[],'fs:f500000b-0000-0000-0000-00000000000b','intermediate',true,'approved'),
('fb02b000-0000-0000-0000-000000000013','Permit-Required Confined Space','A confined space that also has a hazardous atmosphere, engulfment risk, entrapment configuration, or other recognized serious hazard.','Confined space + a serious hazard.',NULL,NULL,NULL,ARRAY['permit-required','confined space','osha']::text[],ARRAY['fs-flashcards','fs-m11']::text[],'fs:f500000b-0000-0000-0000-00000000000b','advanced',true,'approved'),
('fb02b000-0000-0000-0000-000000000014','One-Call (811)','The utility-locate service that must be notified before excavation so existing underground utilities are marked, preventing strikes.','Call before you dig.',NULL,NULL,NULL,ARRAY['811','one-call','utilities','safety']::text[],ARRAY['fs-flashcards','fs-m11']::text[],'fs:f500000b-0000-0000-0000-00000000000b','beginner',true,'approved');
